#include<bits/stdc++.h>
using namespace std;
namespace FastIO {
	char buf[1 << 21], *p1 = buf, *p2 = buf;
#define getchar() (p1 == p2 && (p1 = buf, p2 = (p1 + fread(buf, 1, 1 << 21, stdin))) == p1 ? EOF : *p1++)
	template <typename T> inline T read() { T x = 0, w = 0; char ch = getchar(); while (ch < '0' || ch > '9') w |= (ch == '-'), ch = getchar(); while ('0' <= ch && ch <= '9') x = x * 10 + (ch ^ '0'), ch = getchar(); return w ? -x : x; }
	template <typename T> inline void write(T x) { if (!x) return; write<T>(x / 10), putchar((x % 10) ^ '0'); }
	template <typename T> inline void print(T x) { if (x > 0) write<T>(x); else if (x < 0) putchar('-'), write<T>(-x); else putchar('0'); }
	template <typename T> inline void print(T x, char en) { print<T>(x), putchar(en); }
}; using namespace FastIO;
#undef getchar()
vector<int> v[21];
int id[21];
bool flag[21];
int tmp[4000010];
int main()
{
    int n=read<int>(),m=read<int>(),q=read<int>();
    for(int i=1;i<=m;i++)
    {
        id[i]=i;
        for(int j=1;j<=n;j++)
        {
            int x=read<int>();
            v[i].push_back(x);
        }
    }
    while(q--)
    {
        int op=read<int>(),x=read<int>(),y=read<int>();
        if(op==1)
        {
            if(!flag[x])
            {
                flag[x]=true;
                sort(v[id[x]].begin(),v[id[x]].end());
            }
            if(!flag[y])
            {
                flag[y]=true;
                sort(v[id[y]].begin(),v[id[y]].end());
            }
            if(v[id[x]].back()<=v[id[y]].front())
            {
                continue;
            }
            if(v[id[x]].front()>=v[id[y]].back())
            {
                swap(id[x],id[y]);
                continue;
            }
            merge(v[id[x]].begin(),v[id[x]].end(),v[id[y]].begin(),v[id[y]].end(),tmp+1);
            for(int i=1;i<=n;i++)
            {
                v[id[x]][i-1]=tmp[i];
                v[id[y]][i-1]=tmp[i+n];
            }
        }
        else
        {
            printf("%d\n",v[id[x]][y-1]);
        }
    }
    return 0;
}
